tlDataChunk*
tlPrimGroupChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::Mesh::VERTEXSHADER:
        dch = new tlVertexShaderChunk(&ch);
        break;
    case Pure3D::Mesh::POSITIONLIST:
        dch = new tlPositionListChunk(&ch);
        break;
    case Pure3D::Mesh::NORMALLIST:
        dch = new tlNormalListChunk(&ch);
        break;
    case Pure3D::Mesh::PACKEDNORMALLIST:
        dch = new tlPackedNormalListChunk(&ch);
        break;
    case Pure3D::Mesh::UVLIST:
        dch = new tlUVListChunk(&ch);
        break;
    case Pure3D::Mesh::COLOURLIST:
        dch = new tlColourListChunk(&ch);
        break;
    case Pure3D::Mesh::MULTICOLOURLIST:
        dch = new tlMultiColourListChunk(&ch);
        break;
    case Pure3D::Mesh::STRIPLIST:
        dch = new tlStripListChunk(&ch);
        break;
    case Pure3D::Mesh::INDEXLIST:
        dch = new tlIndexListChunk(&ch);
        break;
    case Pure3D::Mesh::MATRIXLIST:
        dch = new tlMatrixListChunk(&ch);
        break;
    case Pure3D::Mesh::WEIGHTLIST:
        dch = new tlWeightListChunk(&ch);
        break;
    case Pure3D::Mesh::MATRIXPALETTE:
        dch = new tlMatrixPaletteChunk(&ch);
        break;
    case Pure3D::Mesh::INSTANCEINFO:
        dch = new tlInstanceInfoChunk(&ch);
        break;
    case Pure3D::Mesh::MEMORYIMAGEVERTEXLIST:
        dch = new tlPrimGroupMemoryImageVertexChunk(&ch);
        break;
    case Pure3D::Mesh::MEMORYIMAGEINDEXLIST:
        dch = new tlPrimGroupMemoryImageIndexChunk(&ch);
        break;
    case Pure3D::Mesh::MEMORYIMAGEVERTEXDESCRIPTIONLIST:
        dch = new tlPrimGroupMemoryImageVertexDescriptionChunk(&ch);
        break;
    case Pure3D::Mesh::TANGENTLIST:
        dch = new tlTangentListChunk(&ch);
        break;
    case Pure3D::Mesh::BINORMALLIST:
        dch = new tlBinormalListChunk(&ch);
        break;
    case Pure3D::Mesh::OFFSETLIST:
        dch = new tlOffsetListChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

