tlPositionListChunk::~tlPositionListChunk()
{

    if(positions != NULL){
        delete[] positions;
    }
}

tlPositionListChunk::tlPositionListChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Mesh::POSITIONLIST);
    ident = Pure3D::Mesh::POSITIONLIST;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numpositions = f->GetLong();
    positions = new tlPoint[numpositions];
    for(i = 0; i < numpositions; i++)
    {
        positions[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::POSITIONLIST);
    }
}

void
tlPositionListChunk::Init()
{
    ident = Pure3D::Mesh::POSITIONLIST;
    numpositions = 0;
    positions = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::POSITIONLIST);
    }
}

long 
tlPositionListChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numpositions );
    for(i = 0; i < (int)numpositions; i++)
    {
        s += sizeof( positions[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlPositionListChunk&
tlPositionListChunk::operator=(const tlPositionListChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numpositions = a.numpositions;
    if(positions)
    {
        delete positions;
    }
    positions = new tlPoint[numpositions];
    for( i = 0; i < numpositions ; i++ )
    {
        positions[i] = a.positions[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlPositionListChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlPositionListChunk* aptr = dynamic_cast<const tlPositionListChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numpositions == aptr->numpositions))
    {
        return false;
    }
    for(i = 0; i < numpositions; i++)
    {
        if(!(positions[i] == aptr->positions[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlPositionListChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


