tlPositionListChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(numpositions);
    for(i = 0; i < numpositions ; i++)
    {
        positions[i].Write(f);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

