tlUVListChunk::tlUVListChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Mesh::UVLIST);
    ident = Pure3D::Mesh::UVLIST;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numuvs = f->GetLong();
    channel = f->GetLong();
    uvs = new tlUV[numuvs];
    for(i = 0; i < numuvs; i++)
    {
        uvs[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::UVLIST);
    }
}

