long 
tlUVListChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numuvs );
    s += sizeof( channel );
    for(i = 0; i < (int)numuvs; i++)
    {
        s += sizeof( uvs[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlUVListChunk&
tlUVListChunk::operator=(const tlUVListChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numuvs = a.numuvs;
    channel = a.channel;
    if(uvs)
    {
        delete uvs;
    }
    uvs = new tlUV[numuvs];
    for( i = 0; i < numuvs ; i++ )
    {
        uvs[i] = a.uvs[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlUVListChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlUVListChunk* aptr = dynamic_cast<const tlUVListChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numuvs == aptr->numuvs))
    {
        return false;
    }
    if(!(channel == aptr->channel))
    {
        return false;
    }
    for(i = 0; i < numuvs; i++)
    {
        if(!(uvs[i] == aptr->uvs[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlUVListChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


