void
tlUVListChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(numuvs);
        f->PutLong(channel);
    for(i = 0; i < numuvs ; i++)
    {
        uvs[i].Write(f);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlUVListChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlUVListChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  NumUVs  = %ld\n",indent,"",numuvs);
    printf("%*s  Channel = %ld\n",indent,"",channel);
    printf("%*s  UVs:\n",indent,"");
    for( i=0; i < numuvs; i++)
    {
         uvs[i].Print(i, indent + 4);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlUVListChunk::PrintFormatted(int indent)
{
    unsigned int i;
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # NumUVs \n",indent,"",numuvs);
    printf("%*s  int   %12ld # Channel\n",indent,"",channel);
    printf("%*s  # UVs    \n",indent,""); 
    for( i=0; i < numuvs; i++)
    {
         uvs[i].PrintFormatted(i,indent+4);
    }
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

