{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(numindices);
    for(i = 0; i < numindices ; i++)
    {
        f->PutLong(indices[i]);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

