{

    if(primgroupindices != NULL){
        delete[] primgroupindices;
    }
}

tlExpressionOffsetsChunk::tlExpressionOffsetsChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Mesh::EXPRESSIONOFFSETS);
    ident = Pure3D::Mesh::EXPRESSIONOFFSETS;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numprimgroups = f->GetLong();
    numoffsetlists = f->GetLong();
    primgroupindices = new unsigned long[numprimgroups];
    for(i = 0; i < numprimgroups; i++)
    {
        primgroupindices[i] = f->GetLong();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::EXPRESSIONOFFSETS);
    }
}

void
tlExpressionOffsetsChunk::Init()
{
    ident = Pure3D::Mesh::EXPRESSIONOFFSETS;
    numprimgroups = 0;
    numoffsetlists = 0;
    primgroupindices = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::EXPRESSIONOFFSETS);
    }
}

long 
tlExpressionOffsetsChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numprimgroups );
    s += sizeof( numoffsetlists );
    for(i = 0; i < (int)numprimgroups; i++)
    {
        s += sizeof( primgroupindices[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlExpressionOffsetsChunk&
tlExpressionOffsetsChunk::operator=(const tlExpressionOffsetsChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numprimgroups = a.numprimgroups;
    numoffsetlists = a.numoffsetlists;
    if(primgroupindices)
    {
        delete primgroupindices;
    }
    primgroupindices = new unsigned long[numprimgroups];
    for( i = 0; i < numprimgroups ; i++ )
    {
        primgroupindices[i] = a.primgroupindices[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlExpressionOffsetsChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlExpressionOffsetsChunk* aptr = dynamic_cast<const tlExpressionOffsetsChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numprimgroups == aptr->numprimgroups))
    {
        return false;
    }
    if(!(numoffsetlists == aptr->numoffsetlists))
    {
        return false;
    }
    for(i = 0; i < numprimgroups; i++)
    {
        if(!(primgroupindices[i] == aptr->primgroupindices[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlExpressionOffsetsChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


