int tlMatrixListChunk::sortPriority = -1;

tlMatrixListChunk::tlMatrixListChunk()
{
    Init();
}

tlMatrixListChunk::tlMatrixListChunk(const tlMatrixListChunk& ch)
{
    Init();
    *this = ch;
}

tlMatrixListChunk::~tlMatrixListChunk()
{

    if(matrices != NULL){
        delete[] matrices;
    }
}

tlMatrixListChunk::tlMatrixListChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Mesh::MATRIXLIST);
    ident = Pure3D::Mesh::MATRIXLIST;

    tlFile* f = ch->GetFile();
    unsigned int i;

    nummatrices = f->GetLong();
    matrices = new unsigned long[nummatrices];
    for(i = 0; i < nummatrices; i++)
    {
        matrices[i] = f->GetLong();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::MATRIXLIST);
    }
}

void
tlMatrixListChunk::Init()
{
    ident = Pure3D::Mesh::MATRIXLIST;
    nummatrices = 0;
    matrices = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Mesh::MATRIXLIST);
    }
}

long 
tlMatrixListChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( nummatrices );
    for(i = 0; i < (int)nummatrices; i++)
    {
        s += sizeof( matrices[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlMatrixListChunk&
tlMatrixListChunk::operator=(const tlMatrixListChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    nummatrices = a.nummatrices;
    if(matrices)
    {
        delete matrices;
    }
    matrices = new unsigned long[nummatrices];
    for( i = 0; i < nummatrices ; i++ )
    {
        matrices[i] = a.matrices[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlMatrixListChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlMatrixListChunk* aptr = dynamic_cast<const tlMatrixListChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(nummatrices == aptr->nummatrices))
    {
        return false;
    }
    for(i = 0; i < nummatrices; i++)
    {
        if(!(matrices[i] == aptr->matrices[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlMatrixListChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


