void
tlPrimGroupMemoryImageIndexChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(version);
        f->PutLong(param);
        f->PutLong(memoryimageindexsize);
    for(i = 0; i < memoryimageindexsize ; i++)
    {
        f->PutChar(memoryimageindex[i]);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlPrimGroupMemoryImageIndexChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlPrimGroupMemoryImageIndexChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Version              = %ld\n",indent,"",version);
    printf("%*s  Param                = %ld\n",indent,"",param);
    printf("%*s  MemoryImageIndexSize = %ld\n",indent,"",memoryimageindexsize);
    printf("%*s  MemoryImageIndex:\n",indent,"");
    for( i=0; i < memoryimageindexsize; i++)
    {
         printf("%*s    %d %d\n",indent,"",i,memoryimageindex[i]);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlPrimGroupMemoryImageIndexChunk::PrintFormatted(int indent)
{
    unsigned int i;
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # Version             \n",indent,"",version);
    printf("%*s  int   %12ld # Param               \n",indent,"",param);
    printf("%*s  int   %12ld # MemoryImageIndexSize\n",indent,"",memoryimageindexsize);
    printf("%*s  repeat 1 byte  # MemoryImageIndex    \n",indent,"");
    for( i=0; i < memoryimageindexsize; i++)
    {
         printf("%*s    %12d\n",indent,"",memoryimageindex[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

